import uuid
from contextlib import contextmanager
import redis

class StampedePrevention:
    def __init__(self, redis_client: redis.Redis):
        self.redis = redis_client

    @contextmanager
    def distributed_lock(self, key: str, timeout: int = 10):
        lock_key = f"lock:{key}"
        lock_value = str(uuid.uuid4())
        acquired = False

        try:
            acquired = self.redis.set(lock_key, lock_value, ex=timeout, nx=True)
            yield acquired
        finally:
            if acquired:
                lua_script = """
                if redis.call("get", KEYS[1]) == ARGV[1] then
                    return redis.call("del", KEYS[1])
                else
                    return 0
                end
                """
                self.redis.eval(lua_script, 1, lock_key, lock_value)

    def cache_with_lock(self, cache_key: str, loader, ttl: int = 3600):
        cached = self.redis.get(cache_key)
        if cached:
            return json.loads(cached)

        with self.distributed_lock(cache_key) as acquired:
            if acquired:
                data = loader()
                self.redis.setex(cache_key, ttl, json.dumps(data))
                return data
            else:
                time.sleep(0.1)
                cached = self.redis.get(cache_key)
                if cached:
                    return json.loads(cached)
                else:
                    return loader()  # Final fallback
